import { Hono } from 'hono';

const app = new Hono();

app.post('/logout', (c) => {
  // Clear the session cookie
  c.cookie('session', '', {
    expires: new Date(0), // Set expiration date to past
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
  });

  return c.text('Logged out successfully');
});

export default app;

